import './Artists.css'
import SliderArtists from './sliderArtists/SliderArtists';
import Buble from '../../resourses/img/bubule.png';
import Rectage from '../../resourses/img/3.png';
import { useState, useMemo } from 'react';
import Guma from '../../resourses/img/artists/guma2.jfif';
import Nikki from '../../resourses/img/artists/Niki.jpg';
import Nijar from '../../resourses/img/artists/nijan.png';
import Temn from '../../resourses/img/artists/temn.jpg';
import InfoArtists from './infoArtists/InfoArtists'

export default function Artists() {
    const [imageIndex, setImageIndex] = useState(0);

    const onSwap = (data) => {
        setImageIndex(data)
    }


    const artists = useMemo(() => [
        {

            id: 0,
            name: "GUMA",
            inst: "https://www.instagram.com/guma_nastya/",
            vk: "https://vk.com/nastya_gum",
            music: "https://music.apple.com/us/artist/guma/1490238959",
            image: Guma,
        },
        {

            id: 1,
            name: "NIKKI",
            inst: "https://www.instagram.com/nikki_legato/",
            vk: "https://vk.com/guma_official",
            music: "https://music.apple.com/ru/artist/nikki/1590581437",
            image: Nikki,
        },
        {
            id: 2,
            name: "TEMNEE",
            inst: "https://www.instagram.com/temnee_t/",
            vk: "https://vk.com/temnee_mus",
            music: "https://music.apple.com/ru/artist/temnee/1546218952",
            image: Temn,
        },
        {
            id: 3,
            name: "Nijar",
            inst: "https://www.instagram.com/nijar.7/",
            vk: "https://vk.com/nijar",
            music: "https://music.apple.com/ru/artist/nijar/1617608496",
            image: Nijar,
        }
    ], [])


    return (
        <main>
            <SliderArtists imageIndex={imageIndex} onSwap={onSwap} artists={artists} />
            <InfoArtists imageIndex={imageIndex} artists={artists} />
            <span className='buble'><img src={Buble} alt='buble'></img></span>
            <span className='rectage'><img src={Rectage} alt='rectage'></img></span>
        </main>
    )
}