import './Footer.css'
import InstagramIcon from '@mui/icons-material/Instagram';
import Vk from '../../resourses/img/Vkontakte.svg';

export default function Footer() {
    return (
        <footer>
            <div className='footer-info'>
                <div className="footer-info-name">
                    <span>Full Music</span>
                </div>
                <div className='footer-info-contacts'>
                    <div className='margin-info-main'>
                        <span className='margin-info'>
                            example@gmail.com
                        </span>
                        <span className='margin-info'>
                            +380999999999
                        </span>
                    </div>
                    <div className="social">
                        <span><a href="https://www.instagram.com/_fullmusic/"><InstagramIcon /></a></span>
                        <span><a href="https://vk.com/full__music"><img src={Vk} alt="vk" /></a></span>
                    </div>
                </div>
            </div>
            <div className='copyright'>
                <span>Copyright 2022 Full Music. All rights reserved.</span>
            </div>
        </footer>
    )
}